const axios = require('axios');
const cheerio = require('cheerio');

async function fetchMetadata(url) {
    const allowedDomains = ['example.com', 'allowed.net']; // add your allowlist here

    if (isPrivateIp(url)) {
        throw new Error('Private IP address detected');
    }

    try {
        const response = await axios.get(url);
        const $ = cheerio.load(response.data);

        const title = $('title').text();
        const description = $('meta[name="description"]').attr('content');

        const openGraphTags = {};
        $('meta[property^="og:"]').each((index, element) => {
            const property = $(element).attr('property');
            const content = $(element).attr('content');
            openGraphTags[property] = content;
        });

        return { title, description, openGraphTags };
    } catch (error) {
        throw new Error(`Failed to fetch metadata: ${error.message}`);
    }
}

function isPrivateIp(url) {
    const ipRegex = /^(127\.|192\.168\.|10\.)/;
    return ipRegex.test(url);
}

module.exports = { fetchMetadata };